export KUBECONFIG=/mydata/karma/runs/short-fixrun/elasticsearch-transform-scale-upgrade-20260625_013249/bundle/kubeconfig
# Recreate app-events with explicit keyword mapping for service field
kubectl -n elasticsearch exec curl-test -- curl -sk -u "elastic:elasticpass" \
  -XPUT "https://es-http:9200/app-events" \
  -H "Content-Type: application/json" \
  -d '{
    "mappings": {
      "properties": {
        "service": {"type": "keyword"},
        "@timestamp": {"type": "date"}
      }
    }
  }' 2>&1

